#!/usr/bin/env python3

import uuid

class CheckoutError(Exception):
    pass

def validate_cart(cart):
    """
    Validate cart items.
    Each cart item should be a dict with 'id', 'name', 'price', and 'quantity'
    """
    if not cart:
        raise CheckoutError("Cart is empty.")
    for item in cart:
        if not all(key in item for key in ("id", "name", "price", "quantity")):
            raise CheckoutError(f"Invalid cart item: {item}")
        if item["quantity"] <= 0 or item["price"] < 0:
            raise CheckoutError(f"Invalid quantity or price in item: {item}")
    return cart

def apply_discount(cart, discount_code, user):
    """
    Apply discount codes if valid.
    Some discount codes have restrictions:
      - 'SAVE10': available for all users, 10% off
      - 'ADMIN20': admin-only discount, 20% off
      - 'VIP15': available only for users with tier 'VIP', 15% off
    """
    discount_codes = {
        "SAVE10": {"discount": 0.10, "role": None, "tier": None},
        "ADMIN20": {"discount": 0.20, "role": "admin", "tier": None},
        "VIP15": {"discount": 0.15, "role": None, "tier": "VIP"}
    }

    if discount_code is None or discount_code == "":
        return cart, 0.0  # no discount applied

    code_info = discount_codes.get(discount_code)
    if not code_info:
        raise CheckoutError("Invalid discount code.")

    # Check role restrictions
    if code_info["role"] and user.get("role") != code_info["role"]:
        raise CheckoutError("User does not have permission to use this discount code.")
    # Check tier restrictions
    if code_info["tier"] and user.get("tier") != code_info["tier"]:
        raise CheckoutError("User tier does not allow usage of this discount code.")

    discount_rate = code_info["discount"]
    
    # Apply discount to each cart item
    for item in cart:
        original_price = item["price"]
        discounted_price = original_price * (1 - discount_rate)
        item["price"] = discounted_price
    return cart, discount_rate

def calculate_tax(cart, tax_rate=0.08):
    """
    Calculate tax based on the updated cart.
    """
    subtotal = sum(item["price"] * item["quantity"] for item in cart)
    tax = subtotal * tax_rate
    total = subtotal + tax
    return subtotal, tax, total

def process_payment(total_amount, payment_info):
    """
    Process payment. Assume payment_info contains 'card_number', 'expiry', etc.
    For simulation, we'll always succeed if card number is provided.
    """
    if not payment_info.get("card_number"):
        raise CheckoutError("Payment information is incomplete.")
    # Simulate payment processing
    transaction_id = str(uuid.uuid4())
    # Assume payment is successful
    return {"status": "success", "transaction_id": transaction_id, "amount": total_amount}

def create_order(user, cart, subtotal, tax, total, transaction_info, discount_code):
    """
    Create order record and return order id.
    """
    order = {
        "order_id": str(uuid.uuid4()),
        "user_id": user.get("id"),
        "items": cart,
        "subtotal": subtotal,
        "tax": tax,
        "total": total,
        "transaction": transaction_info,
        "discount_code": discount_code
    }
    # In a real system, this would be saved to a database.
    return order

def checkout_process(user, cart, discount_code, payment_info):
    # Step 1: Validate cart items.
    validated_cart = validate_cart(cart)
    
    # Step 2: Apply discount codes.
    discounted_cart, applied_discount_rate = apply_discount(validated_cart, discount_code, user)
    
    # Step 3: Calculate tax.
    subtotal, tax, total = calculate_tax(discounted_cart)
    
    # Step 4: Process payment.
    transaction_info = process_payment(total, payment_info)
    
    # Step 5: Create order record.
    order = create_order(user, discounted_cart, subtotal, tax, total, transaction_info, discount_code)
    
    return order

